{"id":"S05-SRC14-PROJ-S05-0611","cg":"S05-SRC14-CG-1523","star":"天相","section":["二、夹宫格局","（一）财荫夹印","1. 正格"],"core":["S05-SRC14-A-02511","S05-SRC14-A-02512"],"context":[],"format":[],"relations":["S05-SRC14-REL-02533"],"lines":["S05-SRC14-LINE-2834"],"spans":[{"source_atom_id":"S05-SRC14-A-02511","byte_start":187617,"byte_end":187671},{"source_atom_id":"S05-SRC14-A-02512","byte_start":187671,"byte_end":187743}],"roots":["S05-SRC14-A-02511","S05-SRC14-A-02512"],"core_text":"天相左右二宫必分别为巨门及天梁坐守。天梁为荫星，如果巨门化禄，便为“财荫夹印”正格。","context_text":"","routes":[{"a":"S05-SRC14-A-02511","topics":[],"refs":[],"b":[],"z":[]},{"a":"S05-SRC14-A-02512","topics":["FINANCE"],"refs":["S08","S17","S18"],"b":[],"z":[]}],"context_contribution":"NO","direct_event":"NO","direct_endpoint":"NO","direct_score":"NO","relation_target_bundle_status":"PASS","relation_target_added_ids":[],"external_raw_dependency":"NO","embedded_raw_runtime_dependency":"NO","base_contribution_owner_count":1}
